1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface QuoteStep {
5	  op: "quote";
6	  items: { type: string }[];
7	}
8	
9	interface Scenario {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	}
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	};
21	
22	const BLOCK_SIZE = 3;
23	const RUNE_BLOCK_PREMIUM = 60;
24	
25	const typeBasePremium = (type: string, count: number): number => {
26	  if (type === "rune" && count === BLOCK_SIZE) return RUNE_BLOCK_PREMIUM;
27	  return count * BASE_PREMIUMS[type];
28	};
29	
30	const policyBasePremium = (items: { type: string }[]): number => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  let base = 0;
36	  for (const [type, count] of counts) {
37	    base += typeBasePremium(type, count);
38	  }
39	  return base;
40	};
41	
42	const quotePremium = (step: QuoteStep): number => {
43	  const base = policyBasePremium(step.items);
44	  const total = base * (1 + FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
45	  return Math.ceil(Number(total.toFixed(6)));
46	};
47	
48	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
49	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
50	};
